* x2(i)=1+0.5* cos(2*pi*t(i)+4)+cos(4*pi*t(i)+8)+2.0/3* cos(6*pi*t(i)+12);
* x3(i)=1+0.5* cos(2*pi*t(i)+6)+cos(4*pi*t(i)-2.7)+2.0/3* cos(6*pi*t(i)+0.93);
* x4(i)=1+0.5* cos(2*pi*t(i)+1.2)+cos(4*pi*t(i)+4.1)+2.0/3* cos(6*pi*t(i)-7.02);
* end
